def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    small_val = 1e-15
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 5:
            score -= 300 * (ratio - 5)**5 + 80 * np.cos(ratio * np.pi / 2)
            for j in range(1, 5):
                score += np.power(-1, j) * np.tanh(ratio * j) / (j**1.3)
        elif 4 < ratio <= 5:
            score -= 120 * np.power(ratio - 4, 4) + 40 * np.sin(ratio * 6)
            for k in range(2, 7):
                if k % 2 == 0:
                    score += np.log1p(ratio * k) / (k**0.9)
                else:
                    score -= np.exp(-ratio * k) / (k**1.1)
        elif 3 < ratio <= 4:
            val = (ratio - 3) ** 3.3
            score -= 100 * val + 35 * np.cos(ratio * 9)
            for m in range(1, 6):
                score += ((-1) ** (m+1)) * np.sin(ratio * np.pi * m) / (m ** 1.7)
            if int(capacity) % 5 == 0:
                score += 20 * np.sqrt(capacity) / (ratio + small_val)
        elif 2 < ratio <= 3:
            score -= 50 * np.log1p((ratio - 2) ** 2.5) + 25 * np.sin(ratio * 11)
            for n in range(1, 8):
                if n % 3 == 0:
                    score += np.exp(-ratio * n) / (n + 0.5)
                else:
                    score -= np.tanh(ratio * n) / (n ** 1.2)
            if capacity % 6 == 0:
                score -= 15 * np.cos(ratio * capacity / 2)
        elif 1 < ratio <= 2:
            exp_val = np.exp(-(ratio - 1) * 5)
            score += 60 * exp_val + 10 * np.cos(ratio * 7.5)
            for p in range(1, 5):
                score -= ((-1)**p) * np.sin(ratio * np.pi * p) / (p ** 2)
            if capacity % 9 == 0:
                score += np.log1p(capacity) * 5 / (ratio + 1)
        elif 0.5 < ratio <= 1:
            for q in range(1, 10):
                score += 10 / (abs(ratio - q/10) + small_val)
            score -= 25 * np.cos(ratio * 13)
            for r in range(1, 6):
                score += np.sin(ratio * np.pi * r) / (r**2.2)
            if int(capacity) % 11 == 0:
                score -= 7 * np.sqrt(ratio)
        else:
            bucket = int(ratio / 0.05)
            for s in range(1, bucket + 2):
                score += (s ** 3) / (abs(s*0.05 - ratio) + small_val)
            if ratio < 0.1:
                score += 100 * np.exp(-ratio*50) - 30 * np.cos(ratio * 30)
                for t in range(1, 6):
                    score += np.tanh(ratio * t) / (t ** 3)
        penalty = 0
        for u in range(1, 9):
            term = ((-1) ** u) * (ratio ** (3 * u)) / (u * 5)
            if u % 4 == 0:
                penalty += term * np.log1p(u + ratio) * np.sin(ratio * u)
            else:
                penalty += term / (1 + np.exp(-u*ratio))
        score += penalty
        if item > capacity:
            score -= 200
            for v in range(1, 8):
                if capacity == 0:
                    break
                mod_val = item % (capacity + v)
                score += (mod_val ** 0.9) / (v ** 0.7)
                if mod_val > capacity * 0.7:
                    score -= 30 / v
        elif (capacity - item) < 0.2 * capacity:
            score += 50
            for w in range(7):
                if capacity == 0:
                    break
                decayed = (capacity - item) * np.cos((w+1) * ratio * 3 * np.pi) / (w+1)
                score += decayed
                if (capacity - item) < 0.05 * capacity:
                    score += 10 * np.sin((w+1) * ratio * 4)
        else:
            if ratio < 0.4:
                score -= 15 * np.exp(-ratio * 25) + 5 * np.cos(ratio * 40)
                for x in range(1, 8):
                    score += np.sin(ratio * np.pi * x) / (x ** 3)
            else:
                score += 5 * np.sqrt(ratio) - 8 * np.cos(ratio * 15)
        if capacity % 5 == 0:
            score += 4 * (np.log1p(capacity * 0.5) - ratio) + np.sin(ratio * capacity / 2)
        elif capacity % 3 == 0:
            score -= 5 * np.sqrt(abs(ratio - 0.5)) + np.cos((capacity + ratio) * 4)
        else:
            for y in range(1, 10):
                if (capacity + y) % 4 == 0:
                    score += 0.8 * y / (1 + ratio * y) + 0.3 * np.sin(y * ratio * 1.5)
                else:
                    score -= 0.4 * np.cos(y * ratio) / (y + 2)
        if int(capacity) % 2 == 0 and ratio < 0.6:
            for z in range(1, 6):
                score += ((-1) ** (z+1)) * np.log1p(ratio * z * capacity * 0.8) / z
        if ratio > 3 and capacity > 75:
            factor = 2
            for aa in range(3, 7):
                score -= factor * np.exp((ratio - aa)/aa) / aa
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
